services: nginx: image: nginx:1.21.3 ports: - '{{ PORT_HTTP }}:80' volumes: - ../files/volumes/nginx/.huly.nginx:/etc/nginx/conf.d/default.conf restart: unless-stopped container_name: '{{ INSTANCE_CODE }}' networks: - internal - agz-proxy-network mongodb: image: mongo:7-jammy environment: - PUID=1000 - PGID=1000 volumes: - ./db:/data/db restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_mongodb' networks: - internal minio: image: minio/minio:RELEASE.2024-11-07T00-52-20Z command: server /data --address ":9000" --console-address ":9001" volumes: - ./files:/data restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_minio' networks: - internal elastic: image: elasticsearch:7.14.2 command: '/bin/sh -c "./bin/elasticsearch-plugin list | grep -q ingest-attachment || yes | ./bin/elasticsearch-plugin install --silent ingest-attachment;
/usr/local/bin/docker-entrypoint.sh eswrapper"
' volumes: - ./elastic:/usr/share/elasticsearch/data environment: - ELASTICSEARCH_PORT_NUMBER=9200 - BITNAMI_DEBUG=true - discovery.type=single-node - ES_JAVA_OPTS=-Xms1024m -Xmx1024m - http.cors.enabled=true - http.cors.allow-origin=http://localhost:8082 healthcheck: interval: 20s retries: 10 test: curl -s http://localhost:9200/_cluster/health | grep -vq '"status":"red"' restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_elastic' networks: - internal rekoni: image: hardcoreeng/rekoni-service:${HULY_VERSION} environment: - SECRET=${SECRET} deploy: resources: limits: memory: 500M restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_rekoni' networks: - internal transactor: image: hardcoreeng/transactor:${HULY_VERSION} environment: - SERVER_PORT=3333 - SERVER_SECRET=${SECRET} - SERVER_CURSOR_MAXTIMEMS=30000 - DB_URL=mongodb://mongodb:27017 - MONGO_URL=mongodb://mongodb:27017 - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin - FRONT_URL=http://localhost:8087 - ACCOUNTS_URL=http://account:3000 - FULLTEXT_URL=http://fulltext:4700 - STATS_URL=http://stats:4900 - LAST_NAME_FIRST=${LAST_NAME_FIRST:-true} restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_transactor' networks: - internal collaborator: image: hardcoreeng/collaborator:${HULY_VERSION} environment: - COLLABORATOR_PORT=3078 - SECRET=${SECRET} - ACCOUNTS_URL=http://account:3000 - DB_URL=mongodb://mongodb:27017 - STATS_URL=http://stats:4900 - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_collaborator' networks: - internal account: image: hardcoreeng/account:${HULY_VERSION} environment: - SERVER_PORT=3000 - SERVER_SECRET=${SECRET} - DB_URL=mongodb://mongodb:27017 - MONGO_URL=mongodb://mongodb:27017 - TRANSACTOR_URL=ws://transactor:3333;ws${SECURE:+s}://${HOST_ADDRESS}/_transactor - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin - FRONT_URL=http://front:8080 - STATS_URL=http://stats:4900 - MODEL_ENABLED=* - ACCOUNTS_URL=http://localhost:3000 - ACCOUNT_PORT=3000 restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_account' networks: - internal workspace: image: hardcoreeng/workspace:${HULY_VERSION} environment: - SERVER_SECRET=${SECRET} - DB_URL=mongodb://mongodb:27017 - MONGO_URL=mongodb://mongodb:27017 - TRANSACTOR_URL=ws://transactor:3333;ws${SECURE:+s}://${HOST_ADDRESS}/_transactor - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin - MODEL_ENABLED=* - ACCOUNTS_URL=http://account:3000 - STATS_URL=http://stats:4900 restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_workspace' networks: - internal front: image: hardcoreeng/front:${HULY_VERSION} environment: - SERVER_PORT=8080 - SERVER_SECRET=${SECRET} - LOVE_ENDPOINT=http${SECURE:+s}://${HOST_ADDRESS}/_love - ACCOUNTS_URL=http${SECURE:+s}://${HOST_ADDRESS}/_accounts - REKONI_URL=http${SECURE:+s}://${HOST_ADDRESS}/_rekoni - CALENDAR_URL=http${SECURE:+s}://${HOST_ADDRESS}/_calendar - GMAIL_URL=http${SECURE:+s}://${HOST_ADDRESS}/_gmail - TELEGRAM_URL=http${SECURE:+s}://${HOST_ADDRESS}/_telegram - STATS_URL=http${SECURE:+s}://${HOST_ADDRESS}/_stats - UPLOAD_URL=/files - ELASTIC_URL=http://elastic:9200 - COLLABORATOR_URL=ws${SECURE:+s}://${HOST_ADDRESS}/_collaborator - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin - DB_URL=mongodb://mongodb:27017 - MONGO_URL=mongodb://mongodb:27017 - TITLE=${TITLE:-Huly Self Host} - DEFAULT_LANGUAGE=${DEFAULT_LANGUAGE:-en} - LAST_NAME_FIRST=${LAST_NAME_FIRST:-true} - DESKTOP_UPDATES_CHANNEL=selfhost restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_front' networks: - internal fulltext: image: hardcoreeng/fulltext:${HULY_VERSION} environment: - SERVER_SECRET=${SECRET} - DB_URL=mongodb://mongodb:27017 - FULLTEXT_DB_URL=http://elastic:9200 - ELASTIC_INDEX_NAME=huly_storage_index - STORAGE_CONFIG=minio|minio?accessKey=minioadmin&secretKey=minioadmin - REKONI_URL=http://rekoni:4004 - ACCOUNTS_URL=http://account:3000 - STATS_URL=http://stats:4900 restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_fulltext' networks: - internal stats: image: hardcoreeng/stats:${HULY_VERSION} environment: - PORT=4900 - SERVER_SECRET=${SECRET} restart: unless-stopped container_name: '{{ INSTANCE_CODE }}_stats' networks: - internal networks: internal: driver: bridge agz-proxy-network: external: true

server {
    listen 80;
    server_name _;
    location / {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_pass http://front:8080;
    }

    location /_accounts {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        rewrite ^/_accounts(/.*)$ $1 break;
        proxy_pass http://account:3000/;
    }

    location /_collaborator {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        rewrite ^/_collaborator(/.*)$ $1 break;
        proxy_pass http://collaborator:3078/;
    }

    location /_transactor {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        rewrite ^/_transactor(/.*)$ $1 break;
        proxy_pass http://transactor:3333/;
    }

    location ~ ^/eyJ {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_pass http://transactor:3333;
    }

    location /_rekoni {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        rewrite ^/_rekoni(/.*)$ $1 break;
        proxy_pass http://rekoni:4004/;
    }

    location /_stats {
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        rewrite ^/_stats(/.*)$ $1 break;
        proxy_pass http://stats:4900/;
    }
}
